<span class="line"><span style="--shiki-light:#4078F2;--shiki-dark:#61AFEF;">chsrc</span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;"> set</span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;"> pip</span></span>
